rubric.en:
Expected code/algorithm:
div(a, b) {
  if (b == 0) return "eroare";
  if (sign(a) + sign(b) == 0) s = -1;
  else s = 1;
  if (a < 0) a = -a;
  if (b < 0) b = -b;
  q = 0;
  while (a >= b) {
    a = a-b; q = q + 1;
  }
  return s*q;
}

